import React, { useEffect, useState, useRef } from "react";
import { Link } from "react-router-dom";

// components
import Navbar from "components/Navbars/AuthNavbar.js";
import Footer from "components/Footers/Footer.js";

export default function Landing() {
  // ✅ النصوص باللغات
  const texts = [
    "Hello",
    "Bonjour",
    "Ciao",
    "Hola",
    "こんにちは",
    "你好",
    "안녕하세요",
    "नमस्ते",
    "مرحبا"
  ];

  // ✅ state
  const [index, setIndex] = useState(0);
  const [selectedImage, setSelectedImage] = useState(null);
  const [hoveredId, setHoveredId] = useState(null);
  const [navbarHeight, setNavbarHeight] = useState(0);

  // ✅ مراجع للتحكم
  const timeoutRef = useRef(null);
  const containerRef = useRef(null);
  const navbarRef = useRef(null);

  // ✅ تغيير النص كل 2 ثواني
  useEffect(() => {
    const interval = setInterval(() => {
      setIndex((prev) => (prev + 1) % texts.length);
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  // ✅ قياس ارتفاع النافبار
  useEffect(() => {
    // البحث عن عنصر النافبار
    const navbar = document.querySelector('nav');
    if (navbar) {
      const height = navbar.offsetHeight;
      setNavbarHeight(height);
    }

    // في حالة تغيير حجم الشاشة
    const handleResize = () => {
      const navbar = document.querySelector('nav');
      if (navbar) {
        setNavbarHeight(navbar.offsetHeight);
      }
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // ✅ بيانات الصور الثلاث
  const images = [
    {
      id: 1,
      position: "left",
      url: "https://placehold.co/800x600/1a472a/ffffff?text=QR+Code",
      title: "رمز QR",
      description: "طريقة ذكية لبدء الطلب بدون انتظار النادل",
      fullDescription: "يقوم الزبون بمسح رمز QR الموجود على الطاولة، ليتم فتح قائمة الطعام الرقمية مباشرة على هاتفه. يختار الأطباق المفضلة ويضيفها إلى السلة بكل سهولة، ثم يرسل الطلب مباشرة إلى المطبخ.",
      features: ["⚡ مسح سريع خلال ثانية", "📱 قائمة تفاعلية", "🚀 إرسال مباشر للمطبخ"],
      icon: "📱"
    },
    {
      id: 2,
      position: "center",
      url: "https://placehold.co/800x600/0f3b2c/ffffff?text=Waiter",
      title: "العامل والطلبات",
      description: "إدارة فعالة وسريعة للطلبات",
      fullDescription: "يستقبل العامل الطلبات مباشرة على جهازه اللوحي، مع تفاصيل كل طلب: اسم الطبق، الكمية، الملاحظات الخاصة. يتم تحديد مكان الطاولة بدقة، ويظهر ثمن كل طلب بشكل فوري.",
      features: ["📍 تحديد موقع الطاولة", "💰 عرض الأسعار الفورية", "📝 ملاحظات للطاهي"],
      icon: "👨‍🍳"
    },
    {
      id: 3,
      position: "right",
      url: "https://placehold.co/800x600/1e4d3a/ffffff?text=Invoice",
      title: "الفاتورة الذكية",
      description: "حساب آلي دقيق للمجموع",
      fullDescription: "يقوم النظام تلقائياً بحساب إجمالي الطلبات مع الضريبة، ويظهر تفاصيل كل صنف وسعره. يمكن للزبون دفع الفاتورة إلكترونياً عبر التطبيق، أو طلب الفاتورة الورقية.",
      features: ["🧮 حساب المجموع مع الضريبة", "📊 تفاصيل كل صنف", "💳 دفع إلكتروني آمن"],
      icon: "💰"
    }
  ];

  // ✅ دالة محسنة للتعامل مع Hover حسب الموضع
  const handleMouseEnter = (id, position) => {
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
    }

    setHoveredId(id);

    const container = containerRef.current;
    if (!container) return;

    const items = container.children;
    const leftItem = items[0];
    const centerItem = items[1];
    const rightItem = items[2];

    if (position === "left") {
      leftItem.style.flex = "0 1 50%";
      leftItem.style.transformOrigin = "right center";
      centerItem.style.flex = "0 0 25%";
      rightItem.style.flex = "0 0 25%";
    } 
    else if (position === "center") {
      leftItem.style.flex = "0 0 20%";
      centerItem.style.flex = "0 1 60%";
      rightItem.style.flex = "0 0 20%";
      centerItem.style.transformOrigin = "center center";
    } 
    else if (position === "right") {
      leftItem.style.flex = "0 0 25%";
      centerItem.style.flex = "0 0 25%";
      rightItem.style.flex = "0 1 50%";
      rightItem.style.transformOrigin = "left center";
    }

    if (leftItem) leftItem.style.zIndex = position === "left" ? "10" : "1";
    if (centerItem) centerItem.style.zIndex = position === "center" ? "10" : "1";
    if (rightItem) rightItem.style.zIndex = position === "right" ? "10" : "1";
  };

  // ✅ دالة الخروج من Hover
  const handleMouseLeave = () => {
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
    }

    timeoutRef.current = setTimeout(() => {
      setHoveredId(null);
      const container = containerRef.current;
      if (!container) return;

      const items = container.children;
      for (let item of items) {
        item.style.flex = "1";
        item.style.zIndex = "1";
        item.style.transformOrigin = "center center";
      }
    }, 150);
  };

  // تنظيف timeout
  useEffect(() => {
    return () => {
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
      }
    };
  }, []);

  const openModal = (image) => {
    setSelectedImage(image);
    document.body.style.overflow = "hidden";
  };

  const closeModal = () => {
    setSelectedImage(null);
    document.body.style.overflow = "auto";
  };

  return (
    <>
      <Navbar transparent />
      <main>
        {/* ✅ إضافة مسافة علوية تعادل ارتفاع النافبار */}
        <div 
          className="relative flex content-center items-center justify-center min-h-screen"
          style={{ paddingTop: `${navbarHeight}px` }}
        >
          {/* ✅ خلفية سوداء مع تدرج أخضر */}
          <div className="absolute top-0 w-full h-full bg-gradient-to-br from-black via-gray-900 to-green-900">
            <div className="absolute inset-0 opacity-20" style={{
              backgroundImage: `radial-gradient(circle at 2px 2px, #22c55e 1px, transparent 1px)`,
              backgroundSize: '40px 40px'
            }}></div>
          </div>

          {/* ✅ الصور الثلاث */}
          <div className="absolute top-0 w-full h-full" style={{ paddingTop: `${navbarHeight}px` }}>
            <ul 
              ref={containerRef}
              className="w-full h-full flex m-0 p-0" 
              style={{ listStyle: "none" }}
            >
              {images.map((image, idx) => (
                <li
                  key={image.id}
                  className="relative overflow-hidden transition-all duration-500 cursor-pointer"
                  style={{
                    flex: 1,
                    transition: "all 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94)",
                    borderRight: idx < images.length - 1 ? "2px solid rgba(34, 197, 94, 0.3)" : "none",
                    boxShadow: "inset 0 0 50px rgba(0,0,0,0.5)",
                    willChange: "flex",
                    transformOrigin: image.position === "left" ? "right center" : 
                                    image.position === "right" ? "left center" : "center center"
                  }}
                  onClick={() => openModal(image)}
                  onMouseEnter={() => handleMouseEnter(image.id, image.position)}
                  onMouseLeave={handleMouseLeave}
                >
                  <img
                    src={image.url}
                    alt={image.title}
                    className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full object-cover transition-all duration-500"
                    style={{ 
                      transition: "transform 0.5s cubic-bezier(0.25, 0.46, 0.45, 0.94)",
                      transform: hoveredId === image.id ? "translate(-50%, -50%) scale(1.1)" : "translate(-50%, -50%) scale(1)"
                    }}
                  />

                  {/* طبقة تدرج أخضر/أسود */}
                  <div 
                    className="absolute inset-0 transition-all duration-500"
                    style={{
                      background: "linear-gradient(to top, rgba(0, 0, 0, 0.95) 0%, rgba(34, 197, 94, 0.3) 50%, rgba(0, 0, 0, 0) 100%)",
                      transition: "all 0.4s ease",
                      opacity: hoveredId === image.id ? 1 : 0,
                      visibility: hoveredId === image.id ? "visible" : "hidden"
                    }}
                  >
                    <div 
                      className="absolute left-1/2 bottom-0 -translate-x-1/2 w-4/5 text-center transition-all duration-500"
                      style={{
                        transform: hoveredId === image.id ? "translateX(-50%) scale(1)" : "translateX(-50%) scale(0.85)",
                        opacity: hoveredId === image.id ? 1 : 0,
                        visibility: hoveredId === image.id ? "visible" : "hidden",
                        transition: "all 0.5s cubic-bezier(0.34, 1.2, 0.64, 1)"
                      }}
                    >
                      <div className="mb-3">
                        <span className="text-5xl">{image.icon}</span>
                      </div>
                      <h2 className="text-white text-2xl font-bold mb-3" style={{
                        textShadow: "0 0 10px rgba(34, 197, 94, 0.5)",
                        background: "linear-gradient(135deg, #fff 0%, #22c55e 100%)",
                        WebkitBackgroundClip: "text",
                        WebkitTextFillColor: "transparent",
                        backgroundClip: "text"
                      }}>
                        {image.title}
                      </h2>
                      <p className="text-gray-200 text-sm mb-3 leading-relaxed">
                        {image.description}
                      </p>
                      <span className="inline-flex items-center gap-2 text-xs bg-gradient-to-r from-green-600 to-green-800 px-4 py-2 rounded-full text-white font-semibold shadow-lg">
                        <span>اضغط للمزيد</span>
                        <span>→</span>
                      </span>
                    </div>
                  </div>
                </li>
              ))}
            </ul>
          </div>

          {/* ✅ النص فوق الصور */}
          <div className="container relative mx-auto z-10">
            <div className="items-center flex flex-wrap">
              <div className="w-full lg:w-8/12 px-4 ml-auto mr-auto text-center">
                <div className="pr-12">
                  <h1
                    key={texts[index]}
                    className="text-white font-bold text-6xl md:text-7xl transition-all duration-500 mb-6"
                    style={{
                      textShadow: "0 0 30px rgba(34, 197, 94, 0.5), 0 0 60px rgba(34, 197, 94, 0.3)",
                      background: "linear-gradient(135deg, #ffffff 0%, #22c55e 100%)",
                      WebkitBackgroundClip: "text",
                      WebkitTextFillColor: "transparent",
                      backgroundClip: "text"
                    }}
                  >
                    {texts[index]}
                  </h1>
                  <p className="mt-4 text-xl text-gray-200 font-light">
                    مرحباً بك في نظام إدارة المطاعم الذكي
                  </p>
                  <div className="mt-6 flex justify-center gap-4">
                    <div className="w-12 h-1 bg-green-500 rounded-full"></div>
                    <div className="w-12 h-1 bg-gray-500 rounded-full"></div>
                    <div className="w-12 h-1 bg-green-500 rounded-full"></div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* عنصر زخرفي */}
          <div className="absolute bottom-10 left-0 right-0 z-10 flex justify-center gap-2">
            <div className="animate-pulse w-2 h-2 bg-green-500 rounded-full"></div>
            <div className="animate-pulse delay-100 w-2 h-2 bg-green-400 rounded-full"></div>
            <div className="animate-pulse delay-200 w-2 h-2 bg-green-300 rounded-full"></div>
          </div>
        </div>
      </main>
      <Footer />

      {/* ✅ مودال الصورة المكبرة */}
      {selectedImage && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black bg-opacity-95 backdrop-blur-md transition-all duration-300"
          onClick={closeModal}
        >
          <div
            className="relative max-w-4xl w-full bg-gradient-to-br from-gray-900 to-black rounded-2xl overflow-hidden shadow-2xl transform transition-all duration-300 scale-100 border border-green-500/30"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-green-400 via-green-600 to-green-400"></div>

            <button
              onClick={closeModal}
              className="absolute top-4 right-4 z-10 bg-black bg-opacity-70 hover:bg-green-600 text-white w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-110 border border-green-500/50"
            >
              ✕
            </button>

            <div className="flex flex-col md:flex-row">
              <div className="md:w-1/2 bg-gradient-to-br from-gray-800 to-black relative overflow-hidden">
                <div className="absolute inset-0 bg-green-500/10"></div>
                <img
                  src={selectedImage.url}
                  alt={selectedImage.title}
                  className="w-full h-64 md:h-full object-cover relative z-10"
                />
              </div>
              <div className="md:w-1/2 p-8">
                <div className="flex items-center gap-3 mb-4">
                  <span className="text-4xl">{selectedImage.icon}</span>
                  <h2 className="text-3xl font-bold bg-gradient-to-r from-green-400 to-green-600 bg-clip-text text-transparent">
                    {selectedImage.title}
                  </h2>
                </div>
                <p className="text-gray-300 leading-relaxed mb-6">
                  {selectedImage.fullDescription}
                </p>
                <div className="space-y-3 mb-8">
                  {selectedImage.features.map((feature, i) => (
                    <div key={i} className="flex items-center gap-3 text-sm text-gray-200 group">
                      <span className="text-green-500 text-lg group-hover:scale-110 transition-transform">✓</span>
                      <span>{feature}</span>
                    </div>
                  ))}
                </div>
                <div className="border-t border-green-500/30 pt-4">
                  <p className="text-sm text-green-400 flex items-center gap-2">
                    <span className="animate-pulse">✨</span>
                    نظام إدارة ذكي بالكامل
                    <span className="animate-pulse">✨</span>
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
}
